	'''Initializes a dp 2D list and fills it up with values based on whether a coin can be used for the current amount or not.
	'''
	dp=[[0]*len(coin_denoms) for _ in range(target+1)]
	for i in range(target+1):
		for j in range(len(coin_denoms)+1):
			if i==0 and j==0:
				dp[i][j]=0
		elif j==0:
				dp[i][j]=-1
		elif i<0:
				dp[i][j]=-1
		elif j>0 and i==0:
				dp[i][j]=0
			else:
				if coin_denoms[j-1]<=i:
							dp[i][j]=min(dp[i][j-1],1+dp[i-coin_denoms[j-1]][j])
				else:
						dp[i][j]=dp[i][j-1]
