// -*- coding: utf-8-*
#include <bits/stdc++.h>

using namespace std;

class Solution {
public:
	int coinChange(vector<int>& coin_denoms, int target) {
		vector<vector<int>> dp(target+1, vector<int>(coin_denoms.size()+1, -1));
		for (int i = target; i >= 0; --i) {
			for (int j = coin_denoms.size() - 1; j >= 0; --j) {
				if (coin_denoms[j] <= i) {
					dp[i][j] = min(dp[i][j + 1], dp[i - coin_denoms[j]][j] + 1);
				} else {
					dp[i][j] = dp[i][j + 1];
				}
			}
		}
		return dp[target][coin_denoms.size()];
	}
};

int main() {
	ios_base::sync_with_stdio(false); cin.tie(nullptr);
	int target, n;
	cin >> target >> n;
	vector<int> coin_denoms(n);
	for (int i = 0; i < n; ++i) {
		cin >> coin_denoms[i];
	}
	Solution sol;
	cout << sol.coinChange(coin_denoms, target) << endl;
	return 0;
}
